type EditableRow = RowData

interface DataGridEditableCellProps<TData extends EditableRow, TValue = unknown> {
  cell: Cell<TData, TValue>
  className?: string
  emptyLabel?: string
}

interface DataGridEditDialogProps<TData extends EditableRow> {
  table: Table<TData>
  title?: string
  description?: string
  submitLabel?: string
}

function normalizeOptionValue(value: unknown) {
  return value === null || value === undefined ? "" : String(value)
}

function getOptionValue<TData extends EditableRow>(
  editor: DataGridColumnEditor<TData, unknown>,
  value: string
) {
  const matchedOption = editor.options?.find(
    (option) => normalizeOptionValue(option.value) === value
  )

  return matchedOption?.value ?? value
}

function getOptionLabel<TData extends EditableRow>(
  editor: DataGridColumnEditor<TData, unknown>,
  value: unknown
) {
  return editor.options?.find(
    (option) => normalizeOptionValue(option.value) === normalizeOptionValue(value)
  )?.label
}

function getDisplayValue(value: unknown, emptyLabel = "Click to edit") {
  if (typeof value === "string") {
    return value.trim().length > 0 ? value : emptyLabel
  }

  if (typeof value === "number") {
    return new Intl.NumberFormat("en-US").format(value)
  }

  if (typeof value === "boolean") {
    return value ? "Enabled" : "Disabled"
  }

  if (value === null || value === undefined) {
    return emptyLabel
  }

  return String(value)
}

function getEditorDisplayValue<TData extends EditableRow>(
  editor: DataGridColumnEditor<TData, unknown>,
  value: unknown,
  emptyLabel = "Click to edit"
) {
  return getOptionLabel(editor, value) ?? getDisplayValue(value, emptyLabel)
}

function getDefaultInlineEditorProps<TData extends EditableRow>(
  table: Table<TData>,
  row: TData,
  rowId: string,
  columnId: string,
  editor: DataGridColumnEditor<TData, unknown>,
  value: unknown,
  setValue: (value: unknown) => void,
  commit: (value?: unknown) => Promise<boolean>,
  cancel: () => void,
  isEditing: boolean,
  isPending: boolean,
  error?: string | null
): DataGridColumnEditorRenderProps<TData, unknown> {
  return {
    table,
    row,
    rowId,
    columnId,
    value,
    setValue,
    commit,
    cancel,
    isEditing,
    isPending,
    error,
    editor,
  }
}

function renderSelectField<TData extends EditableRow>({
  editor,
  value,
  setValue,
  isPending,
  isInline = false,
  open,
  onOpenChange,
  triggerAutoFocus,
  onTriggerKeyDown,
}: {
  editor: DataGridColumnEditor<TData, unknown>
  value: unknown
  setValue: (value: unknown) => void
  isPending: boolean
  isInline?: boolean
  open?: boolean
  onOpenChange?: (open: boolean) => void
  triggerAutoFocus?: boolean
  onTriggerKeyDown?: (event: ReactKeyboardEvent<HTMLButtonElement>) => void
}) {
  const normalizedValue = normalizeOptionValue(value)

  return (
    <Select
      value={normalizedValue}
      onValueChange={(nextValue) => setValue(getOptionValue(editor, nextValue || ""))}
      disabled={isPending}
      open={open}
      onOpenChange={onOpenChange}
    >
      <SelectTrigger
        className={cn(
          "w-full px-4",
          isInline && "rounded-none border-0 bg-transparent shadow-none focus-visible:ring-0"
        )}
        autoFocus={triggerAutoFocus}
        onKeyDown={onTriggerKeyDown}
      >
        <SelectValue placeholder={editor.placeholder ?? "Select an option"} />
      </SelectTrigger>
      <SelectContent alignItemWithTrigger={false}>
        {(editor.options ?? []).map((option) => {
          const optionValue = normalizeOptionValue(option.value)
          return (
            <SelectItem key={`${optionValue || "empty"}-${option.label}`} value={optionValue}>
              {option.label}
            </SelectItem>
          )
        })}
      </SelectContent>
    </Select>
  )
}

function DataGridInlineSelectEditor<TData extends EditableRow>(
  props: DataGridColumnEditorRenderProps<TData, unknown>
) {
  const { table, row, columnId, editor, value, setValue, commit, cancel, isEditing, isPending } =
    props
  const [open, setOpen] = useState(false)
  const ignoreCloseCancelRef = useRef(false)

  useEffect(() => {
    if (isEditing && !isPending) {
      setOpen(true)
      ignoreCloseCancelRef.current = false
      return
    }

    setOpen(false)
  }, [isEditing, isPending])

  useEffect(() => {
    if (isEditing && !open && !isPending) {
      ignoreCloseCancelRef.current = false
    }
  }, [isEditing, open, isPending])

  if (!isEditing) {
    return (
      <button
        type="button"
        className={cn(
          "text-foreground hover:bg-muted/60 flex min-h-9 w-full items-center rounded-md px-2 py-1 text-left transition-colors",
          !value && "text-muted-foreground"
        )}
        onClick={() => table.options.meta?.editing?.startCellEdit(row, columnId)}
        disabled={isPending}
      >
        {getEditorDisplayValue(editor, value, editor.placeholder ?? "Select an option")}
      </button>
    )
  }

  // eslint-disable-next-line react-hooks/refs
  return renderSelectField({
    editor,
    value,
    setValue: (nextValue) => {
      ignoreCloseCancelRef.current = true
      setValue(nextValue)
      void commit(nextValue)
    },
    isPending,
    isInline: true,
    open,
    onOpenChange: (nextOpen) => {
      setOpen(nextOpen)

      if (!nextOpen && !isPending) {
        if (ignoreCloseCancelRef.current) {
          ignoreCloseCancelRef.current = false
          return
        }

        cancel()
      }
    },
    triggerAutoFocus: true,
    onTriggerKeyDown: (event) => {
      if (event.key === "Escape") {
        event.preventDefault()
        cancel()
      }
    },
  })
}

function renderInlineEditor<TData extends EditableRow>({
  table,
  row,
  rowId,
  columnId,
  editor,
  value,
  setValue,
  commit,
  cancel,
  isEditing,
  isPending,
  error,
}: DataGridColumnEditorRenderProps<TData, unknown>) {
  if (editor.renderInline) {
    return editor.renderInline(
      getDefaultInlineEditorProps(
        table,
        row,
        rowId,
        columnId,
        editor,
        value,
        setValue,
        commit,
        cancel,
        isEditing,
        isPending,
        error
      )
    )
  }

  const handleTextKeyDown = (event: ReactKeyboardEvent<HTMLInputElement>) => {
    if (event.key === "Enter") {
      event.preventDefault()
      void commit()
    }

    if (event.key === "Escape") {
      event.preventDefault()
      cancel()
    }
  }

  if (editor.kind === "text" || editor.kind === "email") {
    if (!isEditing) {
      return (
        <button
          type="button"
          className={cn(
            "text-foreground hover:bg-muted/60 flex w-full items-center rounded-md px-2 py-1 text-left transition-colors",
            !value && "text-muted-foreground"
          )}
          onClick={() => table.options.meta?.editing?.startCellEdit(row, columnId)}
          disabled={isPending}
        >
          {getDisplayValue(value)}
        </button>
      )
    }

    return (
      <Input
        autoFocus
        type={editor.kind}
        value={typeof value === "string" ? value : value == null ? "" : String(value)}
        onChange={(event) => setValue(event.target.value)}
        onBlur={() => void commit()}
        onKeyDown={handleTextKeyDown}
        placeholder={editor.placeholder ?? "Enter a value"}
        disabled={isPending}
        className="rounded-none"
      />
    )
  }

  if (editor.kind === "number") {
    if (!isEditing) {
      return (
        <button
          type="button"
          className={cn(
            "text-foreground hover:bg-muted/60 flex w-full items-center rounded-md px-2 py-1 text-left transition-colors",
            value == null && "text-muted-foreground"
          )}
          onClick={() => table.options.meta?.editing?.startCellEdit(row, columnId)}
          disabled={isPending}
        >
          {getDisplayValue(value)}
        </button>
      )
    }

    return (
      <NumberField
        value={typeof value === "number" ? value : undefined}
        onValueChange={(nextValue) => setValue(nextValue)}
        min={editor.min}
        max={editor.max}
        step={editor.step}
        className="rounded-none"
      >
        <NumberFieldGroup
          className="rounded-none border-0 bg-transparent shadow-none focus-within:ring-0"
          aria-invalid={Boolean(error)}
        >
          <NumberFieldDecrement />
          <NumberFieldInput
            autoFocus
            onBlur={() => void commit()}
            onKeyDown={(event) => {
              if (event.key === "Enter") {
                event.preventDefault()
                void commit()
              }

              if (event.key === "Escape") {
                event.preventDefault()
                cancel()
              }
            }}
          />
          <NumberFieldIncrement />
        </NumberFieldGroup>
      </NumberField>
    )
  }

  if (editor.kind === "select") {
    return (
      <DataGridInlineSelectEditor
        table={table}
        row={row}
        rowId={rowId}
        columnId={columnId}
        editor={editor}
        value={value}
        setValue={setValue}
        commit={commit}
        cancel={cancel}
        isEditing={isEditing}
        isPending={isPending}
        error={error}
      />
    )
  }

  if (editor.kind === "radio") {
    return (
      <RadioGroup
        value={normalizeOptionValue(value)}
        onValueChange={(nextValue) => {
          const parsedValue = getOptionValue(editor, nextValue)
          setValue(parsedValue)
          void commit(parsedValue)
        }}
        className="flex flex-wrap gap-3"
      >
        {(editor.options ?? []).map((option) => {
          const optionValue = normalizeOptionValue(option.value) || option.label
          const optionId = `${rowId}-${columnId}-${optionValue}`

          return (
            <div key={optionId} className="flex items-center gap-2">
              <RadioGroupItem
                value={optionValue}
                id={optionId}
                disabled={isPending || option.disabled}
              />
              <Label htmlFor={optionId} className="text-xs">
                {option.label}
              </Label>
            </div>
          )
        })}
      </RadioGroup>
    )
  }

  if (editor.kind === "checkbox") {
    return (
      <div className="flex min-h-9 items-center justify-center">
        <Checkbox
          checked={value === true}
          onCheckedChange={(nextChecked) => void commit(nextChecked === true)}
          disabled={isPending}
        />
      </div>
    )
  }

  if (editor.kind === "switch") {
    return (
      <div className="flex min-h-9 items-center">
        <Switch
          checked={value === true}
          onCheckedChange={(nextChecked) => void commit(nextChecked === true)}
          disabled={isPending}
        />
      </div>
    )
  }

  if (editor.kind === "rating") {
    return (
      <div className="flex min-h-9 items-center">
        <Rating
          rating={typeof value === "number" ? value : 0}
          editable
          onRatingChange={(nextRating) => void commit(nextRating)}
        />
      </div>
    )
  }

  return (
    <button
      type="button"
      className={cn(
        "text-foreground hover:bg-muted/60 flex w-full items-center rounded-md px-2 py-1 text-left transition-colors",
        !value && "text-muted-foreground"
      )}
      onClick={() => table.options.meta?.editing?.startCellEdit(row, columnId)}
      disabled={isPending}
    >
      {getDisplayValue(value)}
    </button>
  )
}

function renderDialogField<TData extends EditableRow>({
  table,
  row,
  rowId,
  columnId,
  editor,
  value,
  setValue,
  commit,
  cancel,
  isEditing,
  isPending,
  error,
}: DataGridColumnEditorRenderProps<TData, unknown>) {
  if (editor.renderDialog) {
    return editor.renderDialog({
      table,
      row,
      rowId,
      columnId,
      value,
      setValue,
      commit,
      cancel,
      isEditing,
      isPending,
      error,
      editor,
    })
  }

  if (editor.kind === "text" || editor.kind === "email") {
    return (
      <Input
        type={editor.kind}
        value={typeof value === "string" ? value : value == null ? "" : String(value)}
        onChange={(event) => setValue(event.target.value)}
        placeholder={editor.placeholder ?? "Enter a value"}
        disabled={isPending}
      />
    )
  }

  if (editor.kind === "textarea") {
    return (
      <Textarea
        value={typeof value === "string" ? value : value == null ? "" : String(value)}
        onChange={(event) => setValue(event.target.value)}
        placeholder={editor.placeholder ?? "Add details"}
        disabled={isPending}
        className="min-h-24"
      />
    )
  }

  if (editor.kind === "number") {
    return (
      <NumberField
        value={typeof value === "number" ? value : undefined}
        onValueChange={(nextValue) => setValue(nextValue)}
        min={editor.min}
        max={editor.max}
        step={editor.step}
      >
        <NumberFieldGroup aria-invalid={Boolean(error)}>
          <NumberFieldDecrement />
          <NumberFieldInput />
          <NumberFieldIncrement />
        </NumberFieldGroup>
      </NumberField>
    )
  }

  if (editor.kind === "select") {
    return renderSelectField({ editor, value, setValue, isPending, isInline: false })
  }

  if (editor.kind === "radio") {
    return (
      <RadioGroup
        value={normalizeOptionValue(value)}
        onValueChange={(nextValue) => setValue(getOptionValue(editor, nextValue))}
        className="grid gap-2"
      >
        {(editor.options ?? []).map((option) => {
          const optionValue = normalizeOptionValue(option.value) || option.label
          const optionId = `dialog-${rowId}-${columnId}-${optionValue}`

          return (
            <label
              key={optionId}
              htmlFor={optionId}
              className={cn(
                "border-input hover:bg-muted flex cursor-pointer items-start gap-3 rounded-lg border p-3 transition-colors",
                normalizeOptionValue(value) === optionValue && "bg-muted border-primary"
              )}
            >
              <RadioGroupItem
                id={optionId}
                disabled={isPending}
                value={optionValue}
                className="mt-0.5"
              />
              <div className="grid gap-0.5">
                <span className="font-medium">{option.label}</span>
                {option.description ? (
                  <span className="text-muted-foreground text-sm">{option.description}</span>
                ) : null}
              </div>
            </label>
          )
        })}
      </RadioGroup>
    )
  }

  if (editor.kind === "checkbox") {
    const controlId = `dialog-${rowId}-${columnId}`

    return (
      <Field className="gap-3 rounded-lg border p-3">
        <div className="flex items-start justify-between gap-3">
          <div className="space-y-1">
            <FieldLabel htmlFor={controlId}>{editor.label ?? "Toggle option"}</FieldLabel>
            {editor.description ? <FieldDescription>{editor.description}</FieldDescription> : null}
          </div>
          <Checkbox
            id={controlId}
            checked={value === true}
            onCheckedChange={(nextChecked) => setValue(nextChecked === true)}
            disabled={isPending}
          />
        </div>
      </Field>
    )
  }

  if (editor.kind === "switch") {
    const controlId = `dialog-${rowId}-${columnId}`

    return (
      <Field className="gap-3 rounded-lg border p-3">
        <div className="flex items-start justify-between gap-3">
          <div className="space-y-1">
            <FieldLabel htmlFor={controlId}>{editor.label ?? "Toggle option"}</FieldLabel>
            {editor.description ? <FieldDescription>{editor.description}</FieldDescription> : null}
          </div>
          <Switch
            id={controlId}
            checked={value === true}
            onCheckedChange={(nextChecked) => setValue(nextChecked === true)}
            disabled={isPending}
          />
        </div>
      </Field>
    )
  }

  if (editor.kind === "rating") {
    return (
      <div className="flex items-center gap-3">
        <Rating
          rating={typeof value === "number" ? value : 0}
          editable
          showValue
          onRatingChange={(nextRating) => setValue(nextRating)}
        />
      </div>
    )
  }

  return (
    <Input
      value={typeof value === "string" ? value : value == null ? "" : String(value)}
      onChange={(event) => setValue(event.target.value)}
      placeholder={editor.placeholder ?? "Enter a value"}
      disabled={isPending}
    />
  )
}

function renderStaticCellValue<TData extends EditableRow, TValue>(
  cell: Cell<TData, TValue>,
  emptyLabel: string
) {
  const renderedValue = cell.getValue()

  if (typeof renderedValue === "string") {
    return renderedValue.trim().length > 0 ? renderedValue : emptyLabel
  }

  if (renderedValue === null || renderedValue === undefined) {
    return emptyLabel
  }

  return String(renderedValue)
}

export function DataGridEditableCell<TData extends EditableRow, TValue = unknown>({
  cell,
  className,
  emptyLabel = "Click to edit",
}: DataGridEditableCellProps<TData, TValue>) {
  const table = cell.getContext().table
  const editing = table.options.meta?.editing
  const editor = getDataGridColumnEditor(cell.column) as
    | DataGridColumnEditor<TData, unknown>
    | undefined

  if (!editing || !editor) {
    return <div className={className}>{renderStaticCellValue(cell, emptyLabel)}</div>
  }

  const row = cell.row.original
  const rowId = cell.row.id
  const columnId = cell.column.id
  const isEditing = editing.isCellEditing(rowId, columnId)
  const isPending = editing.isCellPending(rowId, columnId)
  const error = editing.getCellError(rowId, columnId)
  const value = editing.getCellDraftValue(row, columnId)

  return (
    <div className={cn("space-y-1", className)}>
      {renderInlineEditor({
        table,
        row,
        rowId,
        columnId,
        editor,
        value,
        setValue: (nextValue) => editing.updateCellDraft(rowId, columnId, nextValue),
        commit: (nextValue) => editing.commitCellEdit(row, columnId, nextValue),
        cancel: () => editing.cancelCellEdit(rowId, columnId),
        isEditing,
        isPending,
        error,
      })}
      {isPending ? (
        <div className="text-muted-foreground flex items-center gap-1 text-xs">
          <Spinner className="size-3" />
          Saving
        </div>
      ) : null}
      {error ? <div className="text-destructive text-xs">{error}</div> : null}
    </div>
  )
}

export function DataGridEditDialog<TData extends EditableRow>({
  table,
  title = "Edit record",
  description = "Update the fields below and save your changes.",
  submitLabel = "Save changes",
}: DataGridEditDialogProps<TData>) {
  const editing = table.options.meta?.editing

  const editableColumns = useMemo(
    () =>
      table.getAllLeafColumns().filter((column) => {
        const editor = getDataGridColumnEditor(column)
        return Boolean(editor && !editor.inlineOnly)
      }),
    [table]
  )

  if (!editing) {
    return null
  }

  const dialogRow = editing.dialogRow
  const dialogRowId = editing.dialogRowId

  return (
    <Dialog
      open={editing.dialogOpen}
      onOpenChange={(open) => {
        if (!open) {
          editing.closeDialog()
        }
      }}
    >
      <DialogContent className="p-0 sm:max-w-2xl">
        <DialogHeader className="px-5 py-4 border-b border-border">
          <DialogTitle>{title}</DialogTitle>
          <DialogDescription>{description}</DialogDescription>
        </DialogHeader>

        <ScrollArea className="h-[calc(90vh-200px)]">
          <div className="px-5 py-4">
            {editing.dialogMessage ? (
              <div className="bg-destructive/10 text-destructive mb-4 rounded-lg border px-3 py-2 text-sm">
                {editing.dialogMessage}
              </div>
            ) : null}

            {dialogRow && dialogRowId ? (
              <div className="flex flex-col gap-4">
                {editableColumns.map((column) => {
                  const editor = getDataGridColumnEditor(column) as
                    | DataGridColumnEditor<TData, unknown>
                    | undefined

                  if (!editor) {
                    return null
                  }

                  const columnId = column.id
                  const error = editing.getDialogError(columnId)
                  const value = editing.getDialogValue(columnId)
                  const isPending = editing.isRowPending(dialogRowId)
                  const renderedField = renderDialogField({
                    table,
                    row: dialogRow,
                    rowId: dialogRowId,
                    columnId,
                    editor,
                    value,
                    setValue: (nextValue) => editing.updateDialogDraft(columnId, nextValue),
                    commit: () => editing.saveDialog(),
                    cancel: editing.closeDialog,
                    isEditing: true,
                    isPending,
                    error,
                  })

                  if (editor.kind === "checkbox" || editor.kind === "switch") {
                    return (
                      <div key={columnId}>
                        {renderedField}
                        {error ? <FieldError>{error}</FieldError> : null}
                      </div>
                    )
                  }

                  return (
                    <Field key={columnId}>
                      <FieldLabel>{editor.label ?? column.id}</FieldLabel>
                      {editor.description ? (
                        <FieldDescription>{editor.description}</FieldDescription>
                      ) : null}
                      {renderedField}
                      {error ? <FieldError>{error}</FieldError> : null}
                    </Field>
                  )
                })}
              </div>
            ) : null}
          </div>
        </ScrollArea>

        <DialogFooter className="px-5 py-2 border-t border-border">
          <Button
            variant="outline"
            onClick={editing.closeDialog}
            disabled={Boolean(dialogRowId && editing.isRowPending(dialogRowId))}
          >
            Cancel
          </Button>
          <Button
            onClick={() => void editing.saveDialog()}
            disabled={Boolean(dialogRowId && editing.isRowPending(dialogRowId))}
          >
            {dialogRowId && editing.isRowPending(dialogRowId) ? (
              <>
                <Spinner />
                Saving
              </>
            ) : (
              submitLabel
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

"use client"

import React, { type ReactNode } from "react"
import { useDataGrid } from "@/components/data-grid/data-grid"

import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Skeleton } from "@/components/ui/skeleton"
import { ChevronLeftIcon, ChevronRightIcon } from "lucide-react"

interface DataGridPaginationProps {
  sizes?: number[]
  sizesInfo?: string
  sizesLabel?: string
  sizesDescription?: string
  sizesSkeleton?: ReactNode
  more?: boolean
  moreLimit?: number
  info?: string
  infoSkeleton?: ReactNode
  className?: string
  rowsPerPageLabel?: string
  previousPageLabel?: string
  nextPageLabel?: string
  ellipsisText?: string
}

function DataGridPagination(props: DataGridPaginationProps): React.JSX.Element {
  const { table, recordCount, isLoading } = useDataGrid()

  const defaultProps: Partial<DataGridPaginationProps> = {
    sizes: [5, 10, 25, 50, 100],
    sizesLabel: "Show",
    sizesDescription: "per page",
    sizesSkeleton: <Skeleton className="h-8 w-44" />,
    moreLimit: 5,
    more: false,
    info: "{from} - {to} of {count}",
    infoSkeleton: <Skeleton className="h-8 w-60" />,
    rowsPerPageLabel: "Rows per page",
    previousPageLabel: "Go to previous page",
    nextPageLabel: "Go to next page",
    ellipsisText: "...",
  }

  const mergedProps: DataGridPaginationProps = { ...defaultProps, ...props }

  const btnBaseClasses = "size-7 p-0 text-sm"
  const btnArrowClasses = btnBaseClasses + " rtl:transform rtl:rotate-180"
  const pageIndex = table.getState().pagination.pageIndex
  const pageSize = table.getState().pagination.pageSize
  const from = pageIndex * pageSize + 1
  const to = Math.min((pageIndex + 1) * pageSize, recordCount)
  const pageCount = table.getPageCount()

  // Replace placeholders in paginationInfo
  const paginationInfo = mergedProps?.info
    ? mergedProps.info
        .replace("{from}", from.toString())
        .replace("{to}", to.toString())
        .replace("{count}", recordCount.toString())
    : `${from} - ${to} of ${recordCount}`

  // Pagination limit logic
  const paginationMoreLimit = mergedProps?.moreLimit || 5

  // Determine the start and end of the pagination group
  const currentGroupStart = Math.floor(pageIndex / paginationMoreLimit) * paginationMoreLimit
  const currentGroupEnd = Math.min(currentGroupStart + paginationMoreLimit, pageCount)

  // Render page buttons based on the current group
  const renderPageButtons = () => {
    const buttons = []
    for (let i = currentGroupStart; i < currentGroupEnd; i++) {
      buttons.push(
        <Button
          key={i}
          size="icon-sm"
          variant="ghost"
          className={cn(btnBaseClasses, "text-muted-foreground", {
            "bg-accent text-accent-foreground": pageIndex === i,
          })}
          onClick={() => {
            if (pageIndex !== i) {
              table.setPageIndex(i)
            }
          }}
        >
          {i + 1}
        </Button>
      )
    }
    return buttons
  }

  // Render a "previous" ellipsis button if there are previous pages to show
  const renderEllipsisPrevButton = () => {
    if (currentGroupStart > 0) {
      return (
        <Button
          size="icon-sm"
          className={btnBaseClasses}
          variant="ghost"
          onClick={() => table.setPageIndex(currentGroupStart - 1)}
        >
          {mergedProps.ellipsisText}
        </Button>
      )
    }
    return null
  }

  // Render a "next" ellipsis button if there are more pages to show after the current group
  const renderEllipsisNextButton = () => {
    if (currentGroupEnd < pageCount) {
      return (
        <Button
          className={btnBaseClasses}
          variant="ghost"
          size="icon-sm"
          onClick={() => table.setPageIndex(currentGroupEnd)}
        >
          {mergedProps.ellipsisText}
        </Button>
      )
    }
    return null
  }

  return (
    <div
      data-slot="data-grid-pagination"
      className={cn(
        "flex grow flex-col flex-wrap items-center justify-between gap-2.5 py-2.5 sm:flex-row sm:py-0",
        mergedProps?.className
      )}
    >
      <div className="order-2 flex flex-wrap items-center space-x-2.5 pb-2.5 sm:order-1 sm:pb-0">
        {isLoading ? (
          mergedProps?.sizesSkeleton
        ) : (
          <>
            <div className="text-muted-foreground text-sm">{mergedProps.rowsPerPageLabel}</div>
            <Select
              value={`${pageSize}`}
              onValueChange={(value) => {
                const newPageSize = Number(value)
                table.setPageSize(newPageSize)
              }}
            >
              <SelectTrigger className="w-14" size="sm">
                <SelectValue />
              </SelectTrigger>
              <SelectContent side="top" className="min-w-18">
                {mergedProps?.sizes?.map((size: number) => (
                  <SelectItem key={size} value={`${size}`}>
                    {size}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </>
        )}
      </div>
      <div className="order-1 flex flex-col items-center justify-center gap-2.5 pt-2.5 sm:order-2 sm:flex-row sm:justify-end sm:pt-0">
        {isLoading ? (
          mergedProps?.infoSkeleton
        ) : (
          <>
            <div className="text-muted-foreground text-sm order-2 text-nowrap sm:order-1">
              {paginationInfo}
            </div>
            {pageCount > 1 && (
              <div className="order-1 flex items-center space-x-1 sm:order-2">
                <Button
                  size="icon-sm"
                  variant="ghost"
                  className={btnArrowClasses}
                  onClick={() => table.previousPage()}
                  disabled={!table.getCanPreviousPage()}
                >
                  <span className="sr-only">{mergedProps.previousPageLabel}</span>
                  <ChevronLeftIcon className="size-4" />
                </Button>

                {renderEllipsisPrevButton()}

                {renderPageButtons()}

                {renderEllipsisNextButton()}

                <Button
                  size="icon-sm"
                  variant="ghost"
                  className={btnArrowClasses}
                  onClick={() => table.nextPage()}
                  disabled={!table.getCanNextPage()}
                >
                  <span className="sr-only">{mergedProps.nextPageLabel}</span>
                  <ChevronRightIcon className="size-4" />
                </Button>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  )
}

export { DataGridPagination, type DataGridPaginationProps }

"use client"

import { type PointerEvent, type ReactNode, useCallback, useEffect, useRef, useState } from "react"
import { useDataGrid } from "./data-grid"
import { ScrollArea as ScrollAreaPrimitive } from "@base-ui/react/scroll-area"

import { cn } from "@/lib/utils"

const MIN_THUMB_SIZE = 24
const FALLBACK_SCROLLBAR_SIZE = 12

const INITIAL_METRICS = {
  hasVerticalOverflow: false,
  headerHeight: 0,
  horizontalScrollbarSize: 0,
  thumbHeight: 0,
  thumbTop: 0,
  trackHeight: 0,
} as const

type DataGridScrollAreaOrientation = "horizontal" | "vertical" | "both"

type ScrollbarMetrics = {
  hasVerticalOverflow: boolean
  headerHeight: number
  horizontalScrollbarSize: number
  thumbHeight: number
  thumbTop: number
  trackHeight: number
}

type ObservedElements = {
  header: HTMLElement | null
  horizontalScrollbar: HTMLElement | null
  table: HTMLElement | null
  tableViewport: HTMLElement | null
}

type DataGridScrollAreaProps = Omit<ScrollAreaPrimitive.Root.Props, "children"> & {
  children: ReactNode
  orientation?: DataGridScrollAreaOrientation
}

function clamp(value: number, min: number, max: number) {
  return Math.min(max, Math.max(min, value))
}

function areMetricsEqual(next: ScrollbarMetrics, prev: ScrollbarMetrics) {
  return (
    next.hasVerticalOverflow === prev.hasVerticalOverflow &&
    next.headerHeight === prev.headerHeight &&
    next.horizontalScrollbarSize === prev.horizontalScrollbarSize &&
    next.thumbHeight === prev.thumbHeight &&
    next.thumbTop === prev.thumbTop &&
    next.trackHeight === prev.trackHeight
  )
}

function applyMetrics(element: HTMLElement, metrics: ScrollbarMetrics) {
  element.style.setProperty("--data-grid-scrollbar-header-height", `${metrics.headerHeight}px`)
  element.style.setProperty("--data-grid-scrollbar-thumb-height", `${metrics.thumbHeight}px`)
  element.style.setProperty("--data-grid-scrollbar-thumb-top", `${metrics.thumbTop}px`)
  element.style.setProperty("--data-grid-scrollbar-track-height", `${metrics.trackHeight}px`)
}

function DataGridScrollArea({
  children,
  className,
  orientation = "both",
  ...props
}: DataGridScrollAreaProps) {
  const { props: dataGridProps } = useDataGrid()
  const containerRef = useRef<HTMLDivElement>(null)
  const viewportRef = useRef<HTMLDivElement | null>(null)
  const dragRef = useRef<{
    pointerId: number
    startScrollTop: number
    startY: number
  } | null>(null)
  const metricsRef = useRef<ScrollbarMetrics>(INITIAL_METRICS)
  const observedElementsRef = useRef<ObservedElements>({
    header: null,
    horizontalScrollbar: null,
    table: null,
    tableViewport: null,
  })

  const showHorizontal = orientation !== "vertical"
  const showVertical = orientation !== "horizontal"
  const usesCustomVerticalScrollbar = showVertical && !!dataGridProps.tableLayout?.headerSticky
  const [hasCustomVerticalOverflow, setHasCustomVerticalOverflow] = useState(false)

  const clearDragState = useCallback(() => {
    dragRef.current = null
    document.body.style.userSelect = ""
    document.body.style.webkitUserSelect = ""
  }, [])

  const resetMetrics = useCallback(() => {
    const container = containerRef.current

    if (container && !areMetricsEqual(INITIAL_METRICS, metricsRef.current)) {
      applyMetrics(container, INITIAL_METRICS)
      metricsRef.current = INITIAL_METRICS
    }

    setHasCustomVerticalOverflow((prev) => (prev ? false : prev))
  }, [])

  const syncCustomVerticalScrollbar = useCallback(() => {
    const container = containerRef.current
    const viewport = viewportRef.current

    if (!container || !viewport || !usesCustomVerticalScrollbar) {
      resetMetrics()
      return
    }

    const { header, horizontalScrollbar } = observedElementsRef.current
    const headerHeight = header?.getBoundingClientRect().height ?? 0
    const viewportHeight = viewport.clientHeight
    const viewportWidth = viewport.clientWidth
    const scrollHeight = viewport.scrollHeight
    const scrollWidth = viewport.scrollWidth
    const hasHorizontalOverflow = showHorizontal && scrollWidth > viewportWidth + 0.5
    const horizontalScrollbarSize = hasHorizontalOverflow
      ? horizontalScrollbar?.offsetHeight || FALLBACK_SCROLLBAR_SIZE
      : 0
    const trackHeight = Math.max(0, viewportHeight - headerHeight - horizontalScrollbarSize)
    const maxScroll = Math.max(0, scrollHeight - viewportHeight)

    let nextMetrics: ScrollbarMetrics

    if (trackHeight === 0 || maxScroll === 0) {
      nextMetrics = {
        hasVerticalOverflow: false,
        headerHeight,
        horizontalScrollbarSize,
        thumbHeight: trackHeight,
        thumbTop: 0,
        trackHeight,
      }
    } else {
      const bodyContentHeight = Math.max(trackHeight, scrollHeight - headerHeight)
      const thumbHeight = clamp(
        trackHeight * (trackHeight / bodyContentHeight),
        MIN_THUMB_SIZE,
        trackHeight
      )
      const maxThumbTop = Math.max(0, trackHeight - thumbHeight)
      const thumbTop = maxThumbTop > 0 ? (viewport.scrollTop / maxScroll) * maxThumbTop : 0

      nextMetrics = {
        hasVerticalOverflow: true,
        headerHeight,
        horizontalScrollbarSize,
        thumbHeight,
        thumbTop,
        trackHeight,
      }
    }

    if (!areMetricsEqual(nextMetrics, metricsRef.current)) {
      applyMetrics(container, nextMetrics)
      metricsRef.current = nextMetrics
    }

    setHasCustomVerticalOverflow((prev) =>
      prev === nextMetrics.hasVerticalOverflow ? prev : nextMetrics.hasVerticalOverflow
    )
  }, [resetMetrics, showHorizontal, usesCustomVerticalScrollbar])

  useEffect(() => {
    const container = containerRef.current
    const viewport = viewportRef.current

    if (!container || !viewport) return

    if (!usesCustomVerticalScrollbar) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      resetMetrics()
      return
    }

    observedElementsRef.current = {
      header: container.querySelector('[data-slot="data-grid-table"] thead') as HTMLElement | null,
      horizontalScrollbar: container.querySelector(
        '[data-slot="data-grid-scrollbar"][data-orientation="horizontal"]'
      ) as HTMLElement | null,
      table: container.querySelector('[data-slot="data-grid-table"]') as HTMLElement | null,
      tableViewport: container.querySelector(
        '[data-slot="data-grid-table-viewport"]'
      ) as HTMLElement | null,
    }

    let frame = 0

    const scheduleSync = () => {
      cancelAnimationFrame(frame)
      frame = window.requestAnimationFrame(syncCustomVerticalScrollbar)
    }

    scheduleSync()
    viewport.addEventListener("scroll", scheduleSync, { passive: true })

    const observer = typeof ResizeObserver === "undefined" ? null : new ResizeObserver(scheduleSync)

    observer?.observe(viewport)
    observedElementsRef.current.header && observer?.observe(observedElementsRef.current.header)
    observedElementsRef.current.table && observer?.observe(observedElementsRef.current.table)
    observedElementsRef.current.tableViewport &&
      observer?.observe(observedElementsRef.current.tableViewport)

    return () => {
      cancelAnimationFrame(frame)
      observer?.disconnect()
      viewport.removeEventListener("scroll", scheduleSync)
      clearDragState()
    }
  }, [clearDragState, resetMetrics, syncCustomVerticalScrollbar, usesCustomVerticalScrollbar])

  const scrollToThumbOffset = (nextThumbTop: number) => {
    const viewport = viewportRef.current
    const { thumbHeight, trackHeight } = metricsRef.current

    if (!viewport) return

    const maxScroll = Math.max(0, viewport.scrollHeight - viewport.clientHeight)
    const maxThumbTop = Math.max(0, trackHeight - thumbHeight)

    if (maxScroll === 0 || maxThumbTop === 0) {
      viewport.scrollTop = 0
      return
    }

    const ratio = clamp(nextThumbTop, 0, maxThumbTop) / maxThumbTop
    viewport.scrollTop = ratio * maxScroll
  }

  const handleThumbPointerDown = (event: PointerEvent<HTMLDivElement>) => {
    const viewport = viewportRef.current

    if (!viewport) return

    event.preventDefault()
    event.stopPropagation()
    event.currentTarget.setPointerCapture(event.pointerId)

    dragRef.current = {
      pointerId: event.pointerId,
      startScrollTop: viewport.scrollTop,
      startY: event.clientY,
    }

    document.body.style.userSelect = "none"
    document.body.style.webkitUserSelect = "none"
  }

  const handleThumbPointerMove = (event: PointerEvent<HTMLDivElement>) => {
    const viewport = viewportRef.current
    const dragState = dragRef.current
    const { thumbHeight, trackHeight } = metricsRef.current

    if (!viewport || !dragState || dragState.pointerId !== event.pointerId) {
      return
    }

    const maxThumbTop = Math.max(0, trackHeight - thumbHeight)
    const maxScroll = Math.max(0, viewport.scrollHeight - viewport.clientHeight)

    if (maxThumbTop === 0 || maxScroll === 0) return

    const deltaY = event.clientY - dragState.startY
    const nextScrollTop = dragState.startScrollTop + (deltaY / maxThumbTop) * maxScroll

    viewport.scrollTop = clamp(nextScrollTop, 0, maxScroll)
  }

  const handleThumbPointerUp = (event: PointerEvent<HTMLDivElement>) => {
    if (dragRef.current?.pointerId !== event.pointerId) return
    clearDragState()
  }

  const handleTrackPointerDown = (event: PointerEvent<HTMLDivElement>) => {
    const { thumbHeight } = metricsRef.current

    if (event.target !== event.currentTarget) return

    event.preventDefault()
    event.stopPropagation()

    const rect = event.currentTarget.getBoundingClientRect()
    const offsetY = event.clientY - rect.top - thumbHeight / 2

    scrollToThumbOffset(offsetY)
  }

  return (
    <div ref={containerRef} className="relative">
      <ScrollAreaPrimitive.Root
        data-slot="data-grid-scroll-area"
        className={cn("relative", className)}
        {...props}
      >
        <ScrollAreaPrimitive.Viewport
          ref={viewportRef}
          data-slot="scroll-area-viewport"
          className="size-full"
        >
          <ScrollAreaPrimitive.Content data-slot="scroll-area-content">
            {children}
          </ScrollAreaPrimitive.Content>
        </ScrollAreaPrimitive.Viewport>

        {showHorizontal && (
          <ScrollAreaPrimitive.Scrollbar
            data-slot="data-grid-scrollbar"
            data-orientation="horizontal"
            orientation="horizontal"
            className="flex touch-none p-px transition-colors select-none data-[orientation=horizontal]:h-2.5 data-[orientation=horizontal]:flex-col data-[orientation=horizontal]:border-t data-[orientation=horizontal]:border-t-transparent data-[orientation=vertical]:h-full data-[orientation=vertical]:w-2 data-[orientation=vertical]:border-s data-[orientation=vertical]:border-s-transparent"
          >
            <ScrollAreaPrimitive.Thumb
              data-slot="data-grid-thumb"
              className="relative flex-1 rounded-full bg-border"
            />
          </ScrollAreaPrimitive.Scrollbar>
        )}

        {showVertical && !usesCustomVerticalScrollbar && (
          <ScrollAreaPrimitive.Scrollbar
            data-slot="data-grid-scrollbar"
            data-orientation="vertical"
            orientation="vertical"
            className="flex touch-none p-px transition-colors select-none data-[orientation=horizontal]:h-2.5 data-[orientation=horizontal]:flex-col data-[orientation=horizontal]:border-t data-[orientation=horizontal]:border-t-transparent data-[orientation=vertical]:h-full data-[orientation=vertical]:w-2 data-[orientation=vertical]:border-s data-[orientation=vertical]:border-s-transparent"
          >
            <ScrollAreaPrimitive.Thumb
              data-slot="data-grid-thumb"
              className="relative flex-1 rounded-full bg-border"
            />
          </ScrollAreaPrimitive.Scrollbar>
        )}
      </ScrollAreaPrimitive.Root>

      {usesCustomVerticalScrollbar && hasCustomVerticalOverflow && (
        <div
          aria-hidden="true"
          className="pointer-events-none absolute inset-e-0 top-(--data-grid-scrollbar-header-height) z-20 h-(--data-grid-scrollbar-track-height)"
        >
          <div
            className="pointer-events-auto relative h-full w-2 touch-none p-px"
            onPointerDown={handleTrackPointerDown}
          >
            <div
              className={cn(
                "absolute end-px w-2 rounded-full bg-border",
                "top-(--data-grid-scrollbar-thumb-top) h-(--data-grid-scrollbar-thumb-height)"
              )}
              onLostPointerCapture={clearDragState}
              onPointerCancel={handleThumbPointerUp}
              onPointerDown={handleThumbPointerDown}
              onPointerMove={handleThumbPointerMove}
              onPointerUp={handleThumbPointerUp}
            />
          </div>
        </div>
      )}
    </div>
  )
}

export { DataGridScrollArea }
export type { DataGridScrollAreaOrientation, DataGridScrollAreaProps }

"use client"

import {
  type CSSProperties,
  Fragment,
  memo,
  type MouseEvent as ReactMouseEvent,
  type ReactNode,
  type TouchEvent as ReactTouchEvent,
  type Ref,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from "react"
import { useDataGrid } from "@/components/data-grid/data-grid"
import {
  type Cell,
  type Column,
  flexRender,
  type Header,
  type HeaderGroup,
  type Row,
  type Table,
} from "@tanstack/react-table"
import { cva } from "class-variance-authority"

import { cn } from "@/lib/utils"
import { Checkbox } from "@/components/ui/checkbox"
import { Spinner } from "@/components/ui/spinner"

const headerCellSpacingVariants = cva("", {
  variants: {
    size: {
      dense: "px-2.5 h-7",
      default: "px-4 h-9",
    },
  },
  defaultVariants: {
    size: "default",
  },
})

const bodyCellSpacingVariants = cva("", {
  variants: {
    size: {
      dense: "px-2.5 py-2",
      default: "px-0 py-0",
    },
  },
  defaultVariants: {
    size: "default",
  },
})

const footerCellSpacingVariants = cva("", {
  variants: {
    size: {
      dense: "px-2.5 py-2",
      default: "px-4 py-2.5",
    },
  },
  defaultVariants: {
    size: "default",
  },
})

function getPinningStyles<TData>(column: Column<TData>): CSSProperties {
  const isPinned = column.getIsPinned()

  return {
    left: isPinned === "left" ? `${column.getStart("left")}px` : undefined,
    right: isPinned === "right" ? `${column.getAfter("right")}px` : undefined,
    position: isPinned ? "sticky" : "relative",
    width: column.getSize(),
    zIndex: isPinned ? 1 : 0,
  }
}

function assignRef<T>(ref: Ref<T> | undefined, value: T | null) {
  if (!ref) return

  if (typeof ref === "function") {
    ref(value)
    return
  }

  ;(ref as { current: T | null }).current = value
}

type DataGridResizeStartEvent = ReactMouseEvent<HTMLDivElement> | ReactTouchEvent<HTMLDivElement>

type DataGridResizeDocumentEvent = globalThis.MouseEvent | globalThis.TouchEvent

function isDataGridTouchEvent(
  event: DataGridResizeStartEvent | DataGridResizeDocumentEvent
): event is ReactTouchEvent<HTMLDivElement> | globalThis.TouchEvent {
  return "touches" in event
}

function getDataGridResizeEventClientX(
  event: DataGridResizeStartEvent | DataGridResizeDocumentEvent
) {
  if (isDataGridTouchEvent(event)) {
    return event.touches[0]?.clientX ?? event.changedTouches[0]?.clientX
  }

  return event.clientX
}

function startDataGridColumnResizeOnEnd<TData>(
  event: DataGridResizeStartEvent,
  header: Header<TData, unknown>,
  table: Table<TData>
) {
  const column = table.getColumn(header.column.id)

  if (!column || !column.getCanResize()) return
  if (isDataGridTouchEvent(event) && event.touches.length > 1) return

  event.persist?.()

  const ownerDocument = event.currentTarget.ownerDocument
  const previousBodyCursor = ownerDocument.body.style.cursor
  const previousDocumentCursor = ownerDocument.documentElement.style.cursor
  const startSize = header.getSize()
  const dragStartClientX = getDataGridResizeEventClientX(event)
  const headerCell = event.currentTarget.closest("th")
  const headerRect = headerCell?.getBoundingClientRect()
  const startOffset =
    headerRect &&
    Number.isFinite(
      table.options.columnResizeDirection === "rtl" ? headerRect.left : headerRect.right
    )
      ? table.options.columnResizeDirection === "rtl"
        ? headerRect.left
        : headerRect.right
      : dragStartClientX

  if (typeof dragStartClientX !== "number" || typeof startOffset !== "number") {
    return
  }

  ownerDocument.body.style.cursor = "col-resize"
  ownerDocument.documentElement.style.cursor = "col-resize"

  const columnSizingStart = header
    .getLeafHeaders()
    .map((leafHeader) => [leafHeader.column.id, leafHeader.column.getSize()] as [string, number])
  const directionMultiplier = table.options.columnResizeDirection === "rtl" ? -1 : 1

  const updateOffset = (clientXPos?: number, commit = false) => {
    if (typeof clientXPos !== "number") return

    const nextColumnSizing: Record<string, number> = {}
    const deltaOffset = (clientXPos - dragStartClientX) * directionMultiplier
    const deltaPercentage = Math.max(deltaOffset / startSize, -0.999999)

    columnSizingStart.forEach(([columnId, headerSize]) => {
      nextColumnSizing[columnId] =
        Math.round(Math.max(headerSize + headerSize * deltaPercentage, 0) * 100) / 100
    })

    table.setColumnSizingInfo((old) => ({
      ...old,
      startOffset,
      startSize,
      deltaOffset,
      deltaPercentage,
      columnSizingStart,
      isResizingColumn: column.id,
    }))

    if (commit) {
      table.setColumnSizing((old) => ({
        ...old,
        ...nextColumnSizing,
      }))
    }
  }

  const endResize = (clientXPos?: number) => {
    updateOffset(clientXPos, true)
    table.setColumnSizingInfo((old) => ({
      ...old,
      isResizingColumn: false,
      startOffset: null,
      startSize: null,
      deltaOffset: null,
      deltaPercentage: null,
      columnSizingStart: [],
    }))
    ownerDocument.body.style.cursor = previousBodyCursor
    ownerDocument.documentElement.style.cursor = previousDocumentCursor
  }

  const mouseMoveHandler = (moveEvent: globalThis.MouseEvent) => {
    updateOffset(moveEvent.clientX)
  }
  const mouseUpHandler = (upEvent: globalThis.MouseEvent) => {
    ownerDocument.removeEventListener("mousemove", mouseMoveHandler)
    ownerDocument.removeEventListener("mouseup", mouseUpHandler)
    endResize(upEvent.clientX)
  }
  const touchMoveHandler = (moveEvent: globalThis.TouchEvent) => {
    if (moveEvent.cancelable) {
      moveEvent.preventDefault()
      moveEvent.stopPropagation()
    }

    updateOffset(getDataGridResizeEventClientX(moveEvent))
  }
  const touchEndHandler = (endEvent: globalThis.TouchEvent) => {
    ownerDocument.removeEventListener("touchmove", touchMoveHandler)
    ownerDocument.removeEventListener("touchend", touchEndHandler)

    if (endEvent.cancelable) {
      endEvent.preventDefault()
      endEvent.stopPropagation()
    }

    endResize(getDataGridResizeEventClientX(endEvent))
  }

  const passiveIfSupported = { passive: false } as const

  if (isDataGridTouchEvent(event)) {
    ownerDocument.addEventListener("touchmove", touchMoveHandler, passiveIfSupported)
    ownerDocument.addEventListener("touchend", touchEndHandler, passiveIfSupported)
  } else {
    ownerDocument.addEventListener("mousemove", mouseMoveHandler, passiveIfSupported)
    ownerDocument.addEventListener("mouseup", mouseUpHandler, passiveIfSupported)
  }

  table.setColumnSizingInfo((old) => ({
    ...old,
    startOffset,
    startSize,
    deltaOffset: 0,
    deltaPercentage: 0,
    columnSizingStart,
    isResizingColumn: column.id,
  }))
}

type DataGridTablePinnedBoundary = "top" | "bottom"

function getDataGridTableRowSections<TData>(table: Table<TData>, rowsPinnable?: boolean) {
  if (!rowsPinnable) {
    return {
      topRows: [] as Row<TData>[],
      centerRows: table.getRowModel().rows as Row<TData>[],
      bottomRows: [] as Row<TData>[],
    }
  }

  return {
    topRows: table.getTopRows() as Row<TData>[],
    centerRows: table.getCenterRows() as Row<TData>[],
    bottomRows: table.getBottomRows() as Row<TData>[],
  }
}

function getDataGridTableResolvedRows<TData>(table: Table<TData>, rowsPinnable?: boolean) {
  const { topRows, centerRows, bottomRows } = getDataGridTableRowSections(table, rowsPinnable)
  const resolvedRows: Array<{
    row: Row<TData>
    pinnedBoundary?: DataGridTablePinnedBoundary
  }> = []

  topRows.forEach((row, index) => {
    resolvedRows.push({
      row,
      pinnedBoundary:
        index === topRows.length - 1 && (centerRows.length > 0 || bottomRows.length > 0)
          ? "top"
          : undefined,
    })
  })

  centerRows.forEach((row) => {
    resolvedRows.push({ row })
  })

  bottomRows.forEach((row, index) => {
    resolvedRows.push({
      row,
      pinnedBoundary:
        index === 0 && (centerRows.length > 0 || topRows.length > 0) ? "bottom" : undefined,
    })
  })

  return resolvedRows
}

