// Context to share sortable listeners from row to handle
type SortableContextValue = ReturnType<typeof useSortable>
const SortableRowContext = createContext<Pick<
  SortableContextValue,
  "attributes" | "listeners"
> | null>(null)

function DataGridTableDndRowHandle({ className }: { className?: string }) {
  const context = useContext(SortableRowContext)

  if (!context) {
    // Fallback if context is not available (shouldn't happen in normal usage)
    return (
      <Button
        variant="ghost"
        size="icon-sm"
        className={cn(
          "size-7 cursor-grab opacity-70 hover:bg-transparent hover:opacity-100 active:cursor-grabbing",
          className
        )}
        disabled
      >
        <GripHorizontalIcon />
      </Button>
    )
  }

  return (
    <Button
      variant="ghost"
      size="icon-sm"
      className={cn(
        "size-7 cursor-grab opacity-70 hover:bg-transparent hover:opacity-100 active:cursor-grabbing",
        className
      )}
      {...context.attributes}
      {...context.listeners}
    >
      <GripHorizontalIcon />
    </Button>
  )
}

function DataGridTableDndRow<TData>({ row }: { row: Row<TData> }) {
  const { transform, transition, setNodeRef, isDragging, attributes, listeners } = useSortable({
    id: row.id,
  })

  const style: CSSProperties = {
    transform: CSS.Transform.toString(transform),
    transition: transition,
    opacity: isDragging ? 0.8 : 1,
    zIndex: isDragging ? 1 : 0,
    position: "relative",
    cursor: isDragging ? "grabbing" : undefined,
  }

  return (
    <SortableRowContext.Provider value={{ attributes, listeners }}>
      <DataGridTableBodyRow row={row} dndRef={setNodeRef} dndStyle={style} key={row.id}>
        {row.getVisibleCells().map((cell: Cell<TData, unknown>, colIndex) => {
          return (
            <DataGridTableBodyRowCell cell={cell} key={colIndex}>
              {flexRender(cell.column.columnDef.cell, cell.getContext())}
            </DataGridTableBodyRowCell>
          )
        })}
      </DataGridTableBodyRow>
    </SortableRowContext.Provider>
  )
}

function DataGridTableDndRows<TData>({
  handleDragEnd,
  dataIds,
  footerContent,
}: {
  handleDragEnd: (event: DragEndEvent) => void
  dataIds: UniqueIdentifier[]
  footerContent?: ReactNode
}) {
  const { table, isLoading, props } = useDataGrid()
  const pagination = table.getState().pagination
  const tableContainerRef = useRef<HTMLDivElement>(null)
  const [isDraggingRow, setIsDraggingRow] = useState(false)

  const sensors = useSensors(
    useSensor(MouseSensor, {}),
    useSensor(TouchSensor, {}),
    useSensor(KeyboardSensor, {})
  )

  useEffect(() => {
    if (!isDraggingRow) return

    const { body, documentElement } = document
    const previousBodyCursor = body.style.cursor
    const previousDocumentCursor = documentElement.style.cursor

    body.style.cursor = "grabbing"
    documentElement.style.cursor = "grabbing"

    return () => {
      body.style.cursor = previousBodyCursor
      documentElement.style.cursor = previousDocumentCursor
    }
  }, [isDraggingRow])

  const modifiers = useMemo(() => {
    const restrictToTableContainer: Modifier = ({ transform, draggingNodeRect }) => {
      if (!tableContainerRef.current || !draggingNodeRect) {
        return transform
      }

      const containerRect = tableContainerRef.current.getBoundingClientRect()
      const { x, y } = transform

      const minX = containerRect.left - draggingNodeRect.left
      const maxX = containerRect.right - draggingNodeRect.right
      const minY = containerRect.top - draggingNodeRect.top
      const maxY = containerRect.bottom - draggingNodeRect.bottom

      return {
        ...transform,
        x: Math.max(minX, Math.min(maxX, x)),
        y: Math.max(minY, Math.min(maxY, y)),
      }
    }

    return [restrictToVerticalAxis, restrictToTableContainer]
  }, [])

  return (
    <DndContext
      id={useId()}
      collisionDetection={closestCenter}
      modifiers={modifiers}
      onDragCancel={() => setIsDraggingRow(false)}
      onDragEnd={(event) => {
        setIsDraggingRow(false)
        handleDragEnd(event)
      }}
      onDragStart={() => setIsDraggingRow(true)}
      sensors={sensors}
    >
      <DataGridTableViewport
        viewportRef={tableContainerRef}
        className={isDraggingRow ? "relative cursor-grabbing [&_*]:cursor-grabbing!" : "relative"}
      >
        <DataGridTableBase>
          <DataGridTableHead>
            {table.getHeaderGroups().map((headerGroup: HeaderGroup<TData>, index) => {
              return (
                <DataGridTableHeadRow headerGroup={headerGroup} key={index}>
                  {headerGroup.headers.map((header, index) => {
                    const { column } = header

                    return (
                      <DataGridTableHeadRowCell header={header} key={index}>
                        {header.isPlaceholder ? null : props.tableLayout?.columnsResizable &&
                          column.getCanResize() ? (
                          <div className="truncate">
                            {flexRender(header.column.columnDef.header, header.getContext())}
                          </div>
                        ) : (
                          flexRender(header.column.columnDef.header, header.getContext())
                        )}
                        {props.tableLayout?.columnsResizable && column.getCanResize() && (
                          <DataGridTableHeadRowCellResize header={header} />
                        )}
                      </DataGridTableHeadRowCell>
                    )
                  })}
                </DataGridTableHeadRow>
              )
            })}
          </DataGridTableHead>

          {(props.tableLayout?.stripped || !props.tableLayout?.rowBorder) && (
            <DataGridTableRowSpacer />
          )}

          <DataGridTableBody>
            {props.loadingMode === "skeleton" && isLoading && pagination?.pageSize ? (
              Array.from({ length: pagination.pageSize }).map((_, rowIndex) => (
                <DataGridTableBodyRowSkeleton key={rowIndex}>
                  {table.getVisibleFlatColumns().map((column, colIndex) => {
                    return (
                      <DataGridTableBodyRowSkeletonCell column={column} key={colIndex}>
                        {column.columnDef.meta?.skeleton}
                      </DataGridTableBodyRowSkeletonCell>
                    )
                  })}
                </DataGridTableBodyRowSkeleton>
              ))
            ) : table.getRowModel().rows.length ? (
              <SortableContext items={dataIds} strategy={verticalListSortingStrategy}>
                {table.getRowModel().rows.map((row: Row<TData>) => {
                  return <DataGridTableDndRow row={row} key={row.id} />
                })}
              </SortableContext>
            ) : (
              <DataGridTableEmpty />
            )}
          </DataGridTableBody>

          {footerContent && <DataGridTableFoot>{footerContent}</DataGridTableFoot>}
        </DataGridTableBase>
      </DataGridTableViewport>
    </DndContext>
  )
}

export { DataGridTableDndRowHandle, DataGridTableDndRows }

"use client"

import {
  memo,
  type ReactNode,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from "react"
import { useDataGrid } from "@/components/data-grid/data-grid"
import {
  DataGridTableBase,
  DataGridTableBody,
  DataGridTableEmpty,
  DataGridTableFoot,
  DataGridTableHead,
  DataGridTableHeadRow,
  DataGridTableHeadRowCell,
  DataGridTableHeadRowCellResize,
  DataGridTableRenderedRow,
  DataGridTableRowSpacer,
  DataGridTableViewport,
  getDataGridTableRowSections,
} from "@/components/data-grid/data-grid-table"
import { flexRender, type HeaderGroup, type Row, type Table } from "@tanstack/react-table"
import {
  useVirtualizer,
  type VirtualItem,
  type Virtualizer,
  type VirtualizerOptions,
} from "@tanstack/react-virtual"

import { cn } from "@/lib/utils"
import { Spinner } from "@/components/ui/spinner"

type DataGridTableVirtualScrollElements = {
  containerElement: HTMLDivElement | null
  scrollElement: HTMLElement | null
}

type DataGridTableVirtualizerInstance = Virtualizer<
  HTMLElement,
  HTMLTableRowElement
>

type DataGridTableVirtualizerOptions<TData> = Omit<
  VirtualizerOptions<HTMLElement, HTMLTableRowElement>,
  "count" | "estimateSize" | "getItemKey" | "getScrollElement"
> & {
  estimateSize?: (index: number, row: Row<TData>) => number
  getItemKey?: (index: number, row: Row<TData>) => string | number
  getScrollElement?: (
    elements: DataGridTableVirtualScrollElements
  ) => HTMLElement | null
}

interface DataGridTableVirtualProps<TData> {
  height?: number | string
  estimateSize?: number
  overscan?: number
  footerContent?: ReactNode
  renderHeader?: boolean
  onFetchMore?: () => void
  isFetchingMore?: boolean
  hasMore?: boolean
  fetchMoreOffset?: number
  virtualizerOptions?: DataGridTableVirtualizerOptions<TData>
}

interface VirtualBodyProps<TData> {
  table: Table<TData>
  columnCount: number
  topRows: Row<TData>[]
  centerRows: Row<TData>[]
  bottomRows: Row<TData>[]
  virtualItems: VirtualItem[]
  totalSize: number
  isVirtualizationEnabled: boolean
  isInfiniteMode: boolean
  isFetchingMore: boolean
  hasMore?: boolean
  loadingMoreMessage: ReactNode
  allRowsLoadedMessage: ReactNode
  measureRowRef?: (element: HTMLTableRowElement | null) => void
}

function DataGridTableVirtualSpacer({
  columnCount,
  height,
}: {
  columnCount: number
  height: number
}) {
  if (height <= 0) return null

  return (
    <tr aria-hidden="true">
      <td colSpan={columnCount} style={{ height, padding: 0 }} />
    </tr>
  )
}

function DataGridTableVirtualStatusRow({
  children,
  className,
  columnCount,
}: {
  children: ReactNode
  className?: string
  columnCount: number
}) {
  return (
    <tr>
      <td
        colSpan={columnCount}
        className={cn(
          "text-muted-foreground py-4 text-center text-sm",
          className
        )}
      >
        {children}
      </td>
    </tr>
  )
}

function DataGridTableVirtualBody<TData>({
  table,
  columnCount,
  topRows,
  centerRows,
  bottomRows,
  virtualItems,
  totalSize,
  isVirtualizationEnabled,
  isInfiniteMode,
  isFetchingMore,
  hasMore,
  loadingMoreMessage,
  allRowsLoadedMessage,
  measureRowRef,
}: VirtualBodyProps<TData>) {
  const totalRows = topRows.length + centerRows.length + bottomRows.length

  if (!totalRows) return <DataGridTableEmpty />

  const hasCenterRows = centerRows.length > 0
  const showFetchingRow = isInfiniteMode && isFetchingMore
  const showCompleteRow = isInfiniteMode && hasMore === false && totalRows > 0
  const hasMiddleSection = hasCenterRows || showFetchingRow || showCompleteRow
  const leadingSpacerHeight =
    isVirtualizationEnabled && hasCenterRows && virtualItems.length > 0
      ? (virtualItems[0]?.start ?? 0)
      : 0
  const trailingSpacerHeight =
    isVirtualizationEnabled && hasCenterRows && virtualItems.length > 0
      ? Math.max(
          0,
          totalSize - (virtualItems[virtualItems.length - 1]?.end ?? 0)
        )
      : 0

  const renderedRows: ReactNode[] = []

  topRows.forEach((row, index) => {
    renderedRows.push(
      <DataGridTableRenderedRow
        key={row.id}
        row={row}
        pinnedBoundary={
          index === topRows.length - 1 && hasMiddleSection ? "top" : undefined
        }
      />
    )
  })

  if (isVirtualizationEnabled) {
    if (leadingSpacerHeight > 0) {
      renderedRows.push(
        <DataGridTableVirtualSpacer
          key="virtual-spacer-start"
          columnCount={columnCount}
          height={leadingSpacerHeight}
        />
      )
    }

    virtualItems.forEach((virtualRow) => {
      const row = centerRows[virtualRow.index]

      if (!row) return

      renderedRows.push(
        <DataGridTableRenderedRow
          key={row.id}
          row={row}
          rowRef={measureRowRef}
        />
      )
    })

    if (trailingSpacerHeight > 0) {
      renderedRows.push(
        <DataGridTableVirtualSpacer
          key="virtual-spacer-end"
          columnCount={columnCount}
          height={trailingSpacerHeight}
        />
      )
    }
  } else {
    centerRows.forEach((row) => {
      renderedRows.push(<DataGridTableRenderedRow key={row.id} row={row} />)
    })
  }

  if (showFetchingRow) {
    renderedRows.push(
      <DataGridTableVirtualStatusRow
        key="virtual-status-loading"
        columnCount={columnCount}
      >
        <div className="flex items-center justify-center gap-2">
          <Spinner className="size-4 opacity-60" />
          {loadingMoreMessage}
        </div>
      </DataGridTableVirtualStatusRow>
    )
  }

  if (showCompleteRow) {
    renderedRows.push(
      <DataGridTableVirtualStatusRow
        key="virtual-status-complete"
        columnCount={columnCount}
        className="py-3 text-xs"
      >
        {allRowsLoadedMessage}
      </DataGridTableVirtualStatusRow>
    )
  }

  bottomRows.forEach((row, index) => {
    renderedRows.push(
      <DataGridTableRenderedRow
        key={row.id}
        row={row}
        pinnedBoundary={
          index === 0 && (topRows.length > 0 || hasMiddleSection)
            ? "bottom"
            : undefined
        }
      />
    )
  })

  return <>{renderedRows}</>
}

/**
 * Memoized virtual body: skip re-renders during active column resize.
 * Column widths update via CSS variables on the <table> element,
 * so the browser handles width changes without React re-renders.
 */
const MemoizedVirtualBody = memo(
  DataGridTableVirtualBody,
  (_prev, next) => !!next.table.getState().columnSizingInfo.isResizingColumn
) as typeof DataGridTableVirtualBody

function DataGridTableVirtual<TData>({
  height,
  estimateSize = 48,
  overscan = 10,
  footerContent,
  renderHeader = true,
  onFetchMore,
  isFetchingMore = false,
  hasMore,
  fetchMoreOffset = 0,
  virtualizerOptions,
}: DataGridTableVirtualProps<TData>) {
  const { table, props } = useDataGrid()
  const { topRows, centerRows, bottomRows } = getDataGridTableRowSections(
    table,
    props.tableLayout?.rowsPinnable
  )
  const columnCount =
    table.getVisibleFlatColumns().length +
    (props.tableLayout?.columnsResizable ? 1 : 0)
  const isInfiniteMode = typeof onFetchMore === "function"
  const [viewportElements, setViewportElements] =
    useState<DataGridTableVirtualScrollElements>({
      containerElement: null,
      scrollElement: null,
    })

  const {
    estimateSize: customEstimateSize,
    getItemKey: customGetItemKey,
    getScrollElement: customGetScrollElement,
    measureElement: customMeasureElement,
    overscan: customOverscan,
    ...virtualizerOptionsRest
  } = virtualizerOptions ?? {}

  const isVirtualizationEnabled = virtualizerOptions?.enabled !== false
  const loadingMoreMessage =
    props.fetchingMoreMessage || props.loadingMessage || "Loading..."
  const allRowsLoadedMessage =
    props.allRowsLoadedMessage || "All records loaded"

  const handleViewportRef = useCallback((node: HTMLDivElement | null) => {
    setViewportElements({
      containerElement: node,
      scrollElement:
        (node?.closest(
          '[data-slot="scroll-area-viewport"]'
        ) as HTMLElement | null) ?? node,
    })
  }, [])

  const usesExternalScrollArea =
    viewportElements.scrollElement !== null &&
    viewportElements.scrollElement !== viewportElements.containerElement

  const resolveScrollElement = useCallback(() => {
    if (customGetScrollElement) {
      return customGetScrollElement(viewportElements)
    }

    return viewportElements.scrollElement
  }, [customGetScrollElement, viewportElements])

  const resolveItemKey = useCallback(
    (index: number) => {
      const row = centerRows[index]

      if (!row) return index

      return customGetItemKey?.(index, row) ?? row.id ?? index
    },
    [centerRows, customGetItemKey]
  )

  const resolveEstimateSize = useCallback(
    (index: number) => {
      const row = centerRows[index]

      return row
        ? (customEstimateSize?.(index, row) ?? estimateSize)
        : estimateSize
    },
    [centerRows, customEstimateSize, estimateSize]
  )

  const virtualizer = useVirtualizer({
    count: centerRows.length,
    getScrollElement: resolveScrollElement,
    getItemKey: resolveItemKey,
    estimateSize: resolveEstimateSize,
    overscan: customOverscan ?? overscan,
    measureElement: customMeasureElement,
    ...virtualizerOptionsRest,
  }) as DataGridTableVirtualizerInstance

  const virtualItems = isVirtualizationEnabled
    ? virtualizer.getVirtualItems()
    : []
  const totalSize = isVirtualizationEnabled ? virtualizer.getTotalSize() : 0
  const measureRowRef =
    isVirtualizationEnabled && customMeasureElement
      ? virtualizer.measureElement
      : undefined
  const resolvedFetchMoreOffset = useMemo(
    () => Math.max(0, fetchMoreOffset),
    [fetchMoreOffset]
  )

  useEffect(() => {
    if (
      !isVirtualizationEnabled ||
      !isInfiniteMode ||
      hasMore === false ||
      isFetchingMore
    ) {
      return
    }

    const lastItem = virtualItems[virtualItems.length - 1]
    if (!lastItem) return

    if (lastItem.index >= centerRows.length - 1 - resolvedFetchMoreOffset) {
      onFetchMore?.()
    }
  }, [
    centerRows.length,
    hasMore,
    isFetchingMore,
    isInfiniteMode,
    isVirtualizationEnabled,
    onFetchMore,
    resolvedFetchMoreOffset,
    virtualItems,
  ])

  return (
    <DataGridTableViewport
      viewportRef={handleViewportRef}
      className={!usesExternalScrollArea ? "block" : undefined}
      style={
        usesExternalScrollArea
          ? undefined
          : { height, overflow: "auto", position: "relative" }
      }
    >
      <DataGridTableBase>
        {renderHeader && (
          <DataGridTableHead>
            {table
              .getHeaderGroups()
              .map((headerGroup: HeaderGroup<TData>, index: number) => (
                <DataGridTableHeadRow headerGroup={headerGroup} key={index}>
                  {headerGroup.headers.map((header, hIndex) => {
                    const { column } = header

                    return (
                      <DataGridTableHeadRowCell header={header} key={hIndex}>
                        {header.isPlaceholder ? null : props.tableLayout
                            ?.columnsResizable && column.getCanResize() ? (
                          <div className="truncate">
                            {flexRender(
                              header.column.columnDef.header,
                              header.getContext()
                            )}
                          </div>
                        ) : (
                          flexRender(
                            header.column.columnDef.header,
                            header.getContext()
                          )
                        )}
                        {props.tableLayout?.columnsResizable &&
                          column.getCanResize() && (
                            <DataGridTableHeadRowCellResize header={header} />
                          )}
                      </DataGridTableHeadRowCell>
                    )
                  })}
                </DataGridTableHeadRow>
              ))}
          </DataGridTableHead>
        )}

        {renderHeader &&
          (props.tableLayout?.stripped || !props.tableLayout?.rowBorder) && (
            <DataGridTableRowSpacer />
          )}

        <DataGridTableBody>
          <MemoizedVirtualBody
            table={table}
            columnCount={columnCount}
            topRows={topRows}
            centerRows={centerRows}
            bottomRows={bottomRows}
            virtualItems={virtualItems}
            totalSize={totalSize}
            isVirtualizationEnabled={isVirtualizationEnabled}
            isInfiniteMode={isInfiniteMode}
            isFetchingMore={isFetchingMore}
            hasMore={hasMore}
            loadingMoreMessage={loadingMoreMessage}
            allRowsLoadedMessage={allRowsLoadedMessage}
            measureRowRef={measureRowRef}
          />
        </DataGridTableBody>

        {footerContent && (
          <DataGridTableFoot>{footerContent}</DataGridTableFoot>
        )}
      </DataGridTableBase>
    </DataGridTableViewport>
  )
}

export { DataGridTableVirtual }
export type {
  DataGridTableVirtualProps,
  DataGridTableVirtualScrollElements,
  DataGridTableVirtualizerOptions,
}

"use client"

import { type Dispatch, type SetStateAction, useCallback, useMemo, useState } from "react"
import {
  type DataGridColumnEditor,
  type DataGridEditingTableMeta,
} from "@/components/data-grid/data-grid"
import { type RowData } from "@tanstack/react-table"

type EditableRow = RowData

export interface EditableDataGridColumn<TData extends EditableRow> {
  id: string
  editor: DataGridColumnEditor<TData, unknown>
}

export interface EditableDataGridCellSaveParams<TData extends EditableRow> {
  rowId: string
  columnId: string
  row: TData
  previousValue: unknown
  value: unknown
  nextRow: TData
}

export interface EditableDataGridRowSaveParams<TData extends EditableRow> {
  rowId: string
  row: TData
  draft: Partial<TData>
  nextRow: TData
}

export interface EditableDataGridErrorContext<TData extends EditableRow> {
  source: "cell" | "dialog"
  rowId: string
  columnId?: string
  row: TData
  message: string
}

export interface UseEditableDataGridOptions<TData extends EditableRow> {
  data: TData[]
  setData: Dispatch<SetStateAction<TData[]>>
  getRowId: (row: TData) => string
  editorColumns: EditableDataGridColumn<TData>[]
  onSaveCell?: (
    params: EditableDataGridCellSaveParams<TData>
  ) => Promise<TData | void> | TData | void
  onSaveRow?: (params: EditableDataGridRowSaveParams<TData>) => Promise<TData | void> | TData | void
  onError?: (error: unknown, context: EditableDataGridErrorContext<TData>) => void
}

function getCellKey(rowId: string, columnId: string) {
  return `${rowId}::${columnId}`
}

function humanizeColumnId(columnId: string) {
  return columnId
    .replace(/([a-z])([A-Z])/g, "$1 $2")
    .replace(/[-_]/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/^./, (value) => value.toUpperCase())
}

function getRecordValue<TData extends EditableRow>(row: TData, columnId: string) {
  return (row as Record<string, unknown>)[columnId]
}

function setRecordValue<TData extends EditableRow>(row: TData, columnId: string, value: unknown) {
  return {
    ...(row as Record<string, unknown>),
    [columnId]: value,
  } as TData
}

function replaceRow<TData extends EditableRow>(
  rows: TData[],
  rowId: string,
  getRowId: (row: TData) => string,
  nextRow: TData
) {
  return rows.map((row) => (getRowId(row) === rowId ? nextRow : row))
}

function isEmptyValue(value: unknown) {
  if (typeof value === "string") {
    return value.trim().length === 0
  }

  if (Array.isArray(value)) {
    return value.length === 0
  }

  return value === null || value === undefined
}

function normalizeErrorMessage(error: unknown, fallback: string) {
  if (error instanceof Error && error.message) {
    return error.message
  }

  if (typeof error === "string" && error.trim().length > 0) {
    return error
  }

  return fallback
}

export function useEditableDataGrid<TData extends EditableRow>({
  data,
  setData,
  getRowId,
  editorColumns,
  onSaveCell,
  onSaveRow,
  onError,
}: UseEditableDataGridOptions<TData>): DataGridEditingTableMeta<TData> {
  const [activeCell, setActiveCell] = useState<{
    rowId: string
    columnId: string
  } | null>(null)
  const [cellDrafts, setCellDrafts] = useState<Record<string, unknown>>({})
  const [cellErrors, setCellErrors] = useState<Record<string, string | undefined>>({})
  const [pendingCells, setPendingCells] = useState<Record<string, boolean>>({})
  const [pendingRows, setPendingRows] = useState<Record<string, boolean>>({})
  const [dialogRowId, setDialogRowId] = useState<string | null>(null)
  const [dialogDraft, setDialogDraft] = useState<Partial<TData> | null>(null)
  const [dialogErrors, setDialogErrors] = useState<Record<string, string | undefined>>({})
  const [dialogMessage, setDialogMessage] = useState<string | null>(null)

  const editorMap = useMemo(
    () => new Map(editorColumns.map((column) => [column.id, column.editor])),
    [editorColumns]
  )

  const findRowById = useCallback(
    (rowId: string) => data.find((row) => getRowId(row) === rowId) ?? null,
    [data, getRowId]
  )

  const dialogRow = useMemo(
    () => (dialogRowId ? findRowById(dialogRowId) : null),
    [dialogRowId, findRowById]
  )

  const getEditor = useCallback((columnId: string) => editorMap.get(columnId), [editorMap])

  const parseValue = useCallback(
    (editor: DataGridColumnEditor<TData, unknown>, value: unknown, row: TData) => {
      if (editor.parse) {
        return editor.parse(value, row)
      }

      switch (editor.kind) {
        case "number": {
          if (typeof value === "number") {
            return value
          }

          if (typeof value === "string") {
            const normalizedValue = value.replace(/,/g, "").trim()
            return normalizedValue.length > 0 ? Number(normalizedValue) : undefined
          }

          return value
        }

        case "checkbox":
        case "switch":
          return value === true

        case "rating":
          return typeof value === "number" ? value : Number(value)

        default:
          return value
      }
    },
    []
  )

  const validateValue = useCallback(
    (
      columnId: string,
      editor: DataGridColumnEditor<TData, unknown>,
      value: unknown,
      row: TData
    ) => {
      const fieldLabel = editor.label ?? humanizeColumnId(columnId)

      if (editor.required && isEmptyValue(value)) {
        return `${fieldLabel} is required.`
      }

      if (editor.kind === "number" && value !== undefined && value !== null) {
        if (typeof value !== "number" || Number.isNaN(value)) {
          return `${fieldLabel} must be a valid number.`
        }

        if (typeof editor.min === "number" && value < editor.min) {
          return `${fieldLabel} must be at least ${editor.min}.`
        }

        if (typeof editor.max === "number" && value > editor.max) {
          return `${fieldLabel} must be at most ${editor.max}.`
        }
      }

      if (editor.validate) {
        return editor.validate(value, row) ?? null
      }

      return null
    },
    []
  )

  const clearCellState = useCallback((rowId: string, columnId: string) => {
    const cellKey = getCellKey(rowId, columnId)

    setCellDrafts((currentDrafts) => {
      if (!(cellKey in currentDrafts)) {
        return currentDrafts
      }

      const nextDrafts = { ...currentDrafts }
      delete nextDrafts[cellKey]
      return nextDrafts
    })

    setCellErrors((currentErrors) => {
      if (!(cellKey in currentErrors)) {
        return currentErrors
      }

      const nextErrors = { ...currentErrors }
      delete nextErrors[cellKey]
      return nextErrors
    })
  }, [])

  const startCellEdit = useCallback(
    (row: TData, columnId: string) => {
      const rowId = getRowId(row)
      if (pendingRows[rowId]) {
        return
      }

      setDialogMessage(null)
      setActiveCell({ rowId, columnId })
      setCellDrafts((currentDrafts) => ({
        ...currentDrafts,
        [getCellKey(rowId, columnId)]: getRecordValue(row, columnId),
      }))
      setCellErrors((currentErrors) => ({
        ...currentErrors,
        [getCellKey(rowId, columnId)]: undefined,
      }))
    },
    [getRowId, pendingRows]
  )

  const cancelCellEdit = useCallback(
    (rowId?: string, columnId?: string) => {
      const target = rowId && columnId ? { rowId, columnId } : activeCell
      if (!target) {
        return
      }

      clearCellState(target.rowId, target.columnId)
      setActiveCell((currentCell) =>
        currentCell?.rowId === target.rowId && currentCell?.columnId === target.columnId
          ? null
          : currentCell
      )
    },
    [activeCell, clearCellState]
  )

  const updateCellDraft = useCallback((rowId: string, columnId: string, value: unknown) => {
    const cellKey = getCellKey(rowId, columnId)

    setCellDrafts((currentDrafts) => ({
      ...currentDrafts,
      [cellKey]: value,
    }))

    setCellErrors((currentErrors) => ({
      ...currentErrors,
      [cellKey]: undefined,
    }))
    setDialogMessage(null)
  }, [])

  const commitCellEdit = useCallback(
    async (row: TData, columnId: string, value?: unknown) => {
      const rowId = getRowId(row)
      const cellKey = getCellKey(rowId, columnId)
      const editor = getEditor(columnId)

      if (!editor || pendingRows[rowId] || pendingCells[cellKey]) {
        return false
      }

      const currentRow = findRowById(rowId) ?? row
      const rawValue =
        value !== undefined ? value : (cellDrafts[cellKey] ?? getRecordValue(currentRow, columnId))
      const parsedValue = parseValue(editor, rawValue, currentRow)
      const validationError = validateValue(columnId, editor, parsedValue, currentRow)

      if (validationError) {
        setCellErrors((currentErrors) => ({
          ...currentErrors,
          [cellKey]: validationError,
        }))
        return false
      }

      const previousValue = getRecordValue(currentRow, columnId)
      const nextRow = setRecordValue(currentRow, columnId, parsedValue)

      if (Object.is(previousValue, parsedValue)) {
        clearCellState(rowId, columnId)
        setActiveCell((currentCell) =>
          currentCell?.rowId === rowId && currentCell?.columnId === columnId ? null : currentCell
        )
        return true
      }

      setPendingCells((currentPendingCells) => ({
        ...currentPendingCells,
        [cellKey]: true,
      }))
      setCellErrors((currentErrors) => ({
        ...currentErrors,
        [cellKey]: undefined,
      }))
      setData((currentRows) => replaceRow(currentRows, rowId, getRowId, nextRow))

      try {
        const savedRow =
          (await onSaveCell?.({
            rowId,
            columnId,
            row: currentRow,
            previousValue,
            value: parsedValue,
            nextRow,
          })) ?? nextRow

        setData((currentRows) => replaceRow(currentRows, rowId, getRowId, savedRow))
        clearCellState(rowId, columnId)
        setActiveCell((currentCell) =>
          currentCell?.rowId === rowId && currentCell?.columnId === columnId ? null : currentCell
        )

        return true
      } catch (error) {
        const message = normalizeErrorMessage(
          error,
          `${editor.label ?? humanizeColumnId(columnId)} could not be saved.`
        )

        setData((currentRows) => replaceRow(currentRows, rowId, getRowId, currentRow))
        setCellErrors((currentErrors) => ({
          ...currentErrors,
          [cellKey]: message,
        }))
        onError?.(error, {
          source: "cell",
          rowId,
          columnId,
          row: currentRow,
          message,
        })

        return false
      } finally {
        setPendingCells((currentPendingCells) => ({
          ...currentPendingCells,
          [cellKey]: false,
        }))
      }
    },
    [
      cellDrafts,
      clearCellState,
      findRowById,
      getEditor,
      getRowId,
      onError,
      onSaveCell,
      parseValue,
      pendingCells,
      pendingRows,
      setData,
      validateValue,
    ]
  )

  const openDialog = useCallback(
    (row: TData) => {
      const rowId = getRowId(row)
      if (pendingRows[rowId]) {
        return
      }

      setDialogRowId(rowId)
      setDialogDraft({
        ...(row as Record<string, unknown>),
      } as Partial<TData>)
      setDialogErrors({})
      setDialogMessage(null)
    },
    [getRowId, pendingRows]
  )

  const closeDialog = useCallback(() => {
    if (dialogRowId && pendingRows[dialogRowId]) {
      return
    }

    setDialogRowId(null)
    setDialogDraft(null)
    setDialogErrors({})
    setDialogMessage(null)
  }, [dialogRowId, pendingRows])

  const updateDialogDraft = useCallback((columnId: string, value: unknown) => {
    setDialogDraft(
      (currentDraft) =>
        ({
          ...(currentDraft ?? {}),
          [columnId]: value,
        }) as Partial<TData>
    )
    setDialogErrors((currentErrors) => ({
      ...currentErrors,
      [columnId]: undefined,
    }))
    setDialogMessage(null)
  }, [])

  const getDialogValue = useCallback(
    (columnId: string) => dialogDraft?.[columnId as keyof TData],
    [dialogDraft]
  )

  const saveDialog = useCallback(async () => {
    if (!dialogRowId || !dialogDraft) {
      return false
    }

    const currentRow = findRowById(dialogRowId)
    if (!currentRow || pendingRows[dialogRowId]) {
      return false
    }

    const nextRow = { ...currentRow } as TData
    const nextErrors: Record<string, string | undefined> = {}

    for (const { id, editor } of editorColumns) {
      if (editor.inlineOnly) {
        continue
      }

      const rawValue = dialogDraft[id as keyof TData] ?? getRecordValue(currentRow, id)
      const parsedValue = parseValue(editor, rawValue, currentRow)
      const validationError = validateValue(id, editor, parsedValue, currentRow)

      if (validationError) {
        nextErrors[id] = validationError
      } else {
        ;(nextRow as Record<string, unknown>)[id] = parsedValue
      }
    }

    if (Object.values(nextErrors).some(Boolean)) {
      setDialogErrors(nextErrors)
      return false
    }

    setDialogErrors({})
    setDialogMessage(null)
    setPendingRows((currentPendingRows) => ({
      ...currentPendingRows,
      [dialogRowId]: true,
    }))
    setData((currentRows) => replaceRow(currentRows, dialogRowId, getRowId, nextRow))

    try {
      const savedRow =
        (await onSaveRow?.({
          rowId: dialogRowId,
          row: currentRow,
          draft: dialogDraft,
          nextRow,
        })) ?? nextRow

      setData((currentRows) => replaceRow(currentRows, dialogRowId, getRowId, savedRow))
      closeDialog()

      return true
    } catch (error) {
      const message = normalizeErrorMessage(error, "The record could not be saved.")

      setData((currentRows) => replaceRow(currentRows, dialogRowId, getRowId, currentRow))
      setDialogMessage(message)
      onError?.(error, {
        source: "dialog",
        rowId: dialogRowId,
        row: currentRow,
        message,
      })

      return false
    } finally {
      setPendingRows((currentPendingRows) => ({
        ...currentPendingRows,
        [dialogRowId]: false,
      }))
    }
  }, [
    closeDialog,
    dialogDraft,
    dialogRowId,
    editorColumns,
    findRowById,
    getRowId,
    onError,
    onSaveRow,
    parseValue,
    pendingRows,
    setData,
    validateValue,
  ])

  const isCellEditing = useCallback(
    (rowId: string, columnId: string) =>
      activeCell?.rowId === rowId && activeCell?.columnId === columnId,
    [activeCell]
  )

  const isCellPending = useCallback(
    (rowId: string, columnId: string) =>
      Boolean(pendingRows[rowId] || pendingCells[getCellKey(rowId, columnId)]),
    [pendingCells, pendingRows]
  )

  const isRowPending = useCallback(
    (rowId: string) =>
      Boolean(
        pendingRows[rowId] ||
        Object.entries(pendingCells).some(
          ([cellKey, isPending]) => isPending && cellKey.startsWith(`${rowId}::`)
        )
      ),
    [pendingCells, pendingRows]
  )

  const isGridPending = useCallback(
    () => Object.values(pendingRows).some(Boolean) || Object.values(pendingCells).some(Boolean),
    [pendingCells, pendingRows]
  )

  const getCellDraftValue = useCallback(
    (row: TData, columnId: string) =>
      cellDrafts[getCellKey(getRowId(row), columnId)] ?? getRecordValue(row, columnId),
    [cellDrafts, getRowId]
  )

  const getCellError = useCallback(
    (rowId: string, columnId: string) => cellErrors[getCellKey(rowId, columnId)],
    [cellErrors]
  )

  const getDialogError = useCallback((columnId: string) => dialogErrors[columnId], [dialogErrors])

  const clearDialogMessage = useCallback(() => {
    setDialogMessage(null)
  }, [])

  return useMemo(
    () => ({
      activeCell,
      dialogOpen: Boolean(dialogRowId && dialogDraft),
      dialogRow,
      dialogRowId,
      dialogDraft,
      dialogErrors,
      dialogMessage,
      startCellEdit,
      cancelCellEdit,
      updateCellDraft,
      commitCellEdit,
      isCellEditing,
      isCellPending,
      getCellDraftValue,
      getCellError,
      openDialog,
      closeDialog,
      updateDialogDraft,
      saveDialog,
      getDialogValue,
      getDialogError,
      clearDialogMessage,
      isRowPending,
      isGridPending,
    }),
    [
      activeCell,
      cancelCellEdit,
      clearDialogMessage,
      closeDialog,
      commitCellEdit,
      dialogDraft,
      dialogErrors,
      dialogMessage,
      dialogRow,
      dialogRowId,
      getCellDraftValue,
      getCellError,
      getDialogError,
      getDialogValue,
      isCellEditing,
      isCellPending,
      isGridPending,
      isRowPending,
      openDialog,
      saveDialog,
      startCellEdit,
      updateCellDraft,
      updateDialogDraft,
    ]
  )
}

"use client"

import { useState } from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import { StarIcon } from "lucide-react"

const ratingVariants = cva("flex items-center", {
  variants: {
    size: {
      sm: "gap-2",
      default: "gap-2.5",
      lg: "gap-3",
    },
  },
  defaultVariants: {
    size: "default",
  },
})

const starVariants = cva("", {
  variants: {
    size: {
      sm: "w-4 h-4",
      default: "w-5 h-5",
      lg: "w-6 h-6",
    },
  },
  defaultVariants: {
    size: "default",
  },
})

const valueVariants = cva("text-muted-foreground w-5", {
  variants: {
    size: {
      sm: "text-xs",
      default: "text-sm",
      lg: "text-base",
    },
  },
  defaultVariants: {
    size: "default",
  },
})

function Rating({
  rating,
  maxRating = 5,
  size,
  className,
  starClassName,
  showValue = false,
  editable = false,
  onRatingChange,
  ...props
}: React.ComponentProps<"div"> &
  VariantProps<typeof ratingVariants> & {
    /**
     * Current rating value (supports decimal values for partial stars)
     */
    rating: number
    /**
     * Maximum rating value (number of stars to show)
     */
    maxRating?: number
    /**
     * Whether to show the numeric rating value
     */
    showValue?: boolean
    /**
     * Class name for the value span
     */
    starClassName?: string
    /**
     * Whether the rating is editable (clickable)
     */
    editable?: boolean
    /**
     * Callback function called when rating changes
     */
    onRatingChange?: (rating: number) => void
  }) {
  const [hoveredRating, setHoveredRating] = useState<number | null>(null)
  const displayRating = editable && hoveredRating !== null ? hoveredRating : rating

  const handleStarClick = (starRating: number) => {
    if (editable && onRatingChange) {
      onRatingChange(starRating)
    }
  }

  const handleStarMouseEnter = (starRating: number) => {
    if (editable) {
      setHoveredRating(starRating)
    }
  }

  const handleStarMouseLeave = () => {
    if (editable) {
      setHoveredRating(null)
    }
  }

  const renderStars = () => {
    const stars = []

    for (let i = 1; i <= maxRating; i++) {
      const filled = displayRating >= i
      const partiallyFilled = displayRating > i - 1 && displayRating < i
      const fillPercentage = partiallyFilled ? (displayRating - (i - 1)) * 100 : 0

      stars.push(
        <div
          key={i}
          className={cn("relative", editable && "cursor-pointer")}
          onClick={() => handleStarClick(i)}
          onMouseEnter={() => handleStarMouseEnter(i)}
          onMouseLeave={handleStarMouseLeave}
        >
          {/* Background star (empty) */}
          <StarIcon className={cn(starVariants({ size }), "text-muted-foreground/30")} />

          {/* Filled star */}
          <div
            className="absolute inset-0 overflow-hidden"
            style={{
              width: filled ? "100%" : `${fillPercentage}%`,
            }}
          >
            <StarIcon
              data-slot="rating-star-filled"
              className={cn(starVariants({ size }), "fill-yellow-400 text-yellow-400")}
            />
          </div>
        </div>
      )
    }

    return stars
  }

  return (
    <div data-slot="rating" className={cn(ratingVariants({ size }), className)} {...props}>
      <div className="flex items-center">{renderStars()}</div>
      {showValue && (
        <span data-slot="rating-value" className={cn(valueVariants({ size }), starClassName)}>
          {displayRating.toFixed(1)}
        </span>
      )}
    </div>
  )
}

export { Rating }
